import{_ as a,c as e,o as m,b as t}from"./app.c18e3cbe.js";const v='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-08T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/5/index.md"}',r={},p=t('<div class="stanza"><a href="#s3.5" id="s3.5" class="num">3.5</a><div class="sans"><p>\u090F\u0935\u0902 \u0927\u094D\u092F\u093E\u0928\u093E\u0916\u094D\u092F\u092E\u093E\u0923\u0935\u092E\u0941\u092A\u093E\u092F\u0902 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u094D\u092F \u0924\u0926\u0947\u0915\u092F\u094B\u0917\u0915\u094D\u0937\u0947\u092E\u093E\u0928\u094D \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0927\u093E\u0930\u0923\u093E\u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0939\u093E\u0930\u0938\u092E\u093E\u0927\u0940\u0928\u094D \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u092F\u0924\u093F\u2014</p><blockquote><p><strong>\u0928\u093E\u0921\u0940\u0938\u0902\u0939\u093E\u0930\u092D\u0942\u0924\u091C\u092F\u092D\u0942\u0924\u0915\u0948\u0935\u0932\u094D\u092F\u092D\u0942\u0924\u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u093E\u0928\u093F\u0965\u096B\u0965</strong></p></blockquote><p>\u092F\u094B\u0917\u093F\u0928\u093E \u092D\u093E\u0935\u0928\u0940\u092F\u093E\u0928\u0940\u0924\u093F \u0936\u0947\u0937\u0903\u0964 \u0928\u093E\u0921\u0940\u0928\u093E\u0902 \u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u093E\u0926\u093F\u0935\u093E\u0939\u093F\u0928\u0940\u0928\u093E\u0902 \u0938\u0941\u0937\u0940\u0923\u093E\u0902 \u0938\u0902\u0939\u093E\u0930\u0903 \u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E\u0915\u0924\u094D\u0930\u094B\u0926\u093E\u0928\u0935\u0939\u094D\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u093F \u092E\u0927\u094D\u092F\u0928\u093E\u0921\u094D\u092F\u093E\u0902 \u0935\u093F\u0932\u0940\u0928\u0924\u093E\u092A\u093E\u0926\u0928\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0924\u094D\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0905\u092A\u0938\u0935\u094D\u092F\u0947\u0928 \u092A\u0942\u0930\u094D\u092F\u0947\u0924 \u0938\u0935\u094D\u092F\u0947\u0928\u0948\u0935 \u0935\u093F\u0930\u0947\u091A\u092F\u0947\u0924\u094D\u0964<br> \u0928\u093E\u0921\u0940\u0938\u0902\u0936\u094B\u0927\u0928\u0902 \u091A\u0948\u0924\u0928\u094D\u092E\u094B\u0915\u094D\u0937\u092E\u093E\u0930\u094D\u0917\u092A\u0925\u0938\u094D\u092F \u091A\u0965<br> \u0930\u0947\u091A\u0928\u093E\u0924\u094D\u092A\u0942\u0930\u0923\u093E\u0926\u094D\u0930\u094B\u0927\u093E\u0924\u094D\u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0938\u094D\u0924\u094D\u0930\u093F\u0927\u093E \u0938\u094D\u092E\u0943\u0924\u0903\u0964<br> \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u093E \u092C\u0939\u093F\u0930\u0947\u0924\u0947 \u0924\u0941 \u092A\u0941\u0928\u0936\u094D\u091A\u093E\u092D\u094D\u092F\u0928\u094D\u0924\u0930\u0947 \u0924\u094D\u0930\u092F\u0903\u0965<br> \u0906\u092D\u094D\u092F\u0928\u094D\u0924\u0930\u0947\u0923 \u0930\u0947\u091A\u094D\u092F\u0947\u0924 \u092A\u0942\u0930\u094D\u092F\u0947\u0924\u093E\u092D\u094D\u092F\u0928\u094D\u0924\u0930\u0947\u0923 \u0924\u0941\u0964<br> \u0928\u093F\u0937\u094D\u0915\u092E\u094D\u092A\u0902 \u0915\u0941\u092E\u094D\u092D\u0915\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u0915\u093E\u0930\u094D\u092F\u093E\u0936\u094D\u091A\u093E\u092D\u094D\u092F\u0928\u094D\u0924\u0930\u093E\u0938\u094D\u0924\u094D\u0930\u092F\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u0942\u0924\u093E\u0928\u093E\u0902 \u092A\u0943\u0925\u093F\u0935\u094D\u092F\u093E\u0926\u0940\u0928\u093E\u0902 \u091C\u092F\u094B \u0927\u093E\u0930\u0923\u093E\u092D\u093F\u0930\u094D\u0935\u0936\u0940\u0915\u093E\u0930\u0903\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u0935\u093E\u092F\u0935\u0940 \u0927\u093E\u0930\u0923\u093E\u0919\u094D\u0917\u0941\u0937\u094D\u0920 \u0906\u0917\u094D\u0928\u0947\u092F\u0940 \u0928\u093E\u092D\u093F\u092E\u0927\u094D\u092F\u0924\u0903\u0964<br> \u092E\u093E\u0939\u0947\u092F\u0940 \u0915\u0923\u094D\u0920\u0926\u0947\u0936\u0947 \u0924\u0941 \u0935\u093E\u0930\u0941\u0923\u0940 \u0918\u0923\u094D\u091F\u093F\u0915\u093E\u0936\u094D\u0930\u092F\u093E\u0965<br> \u0906\u0915\u093E\u0936\u0927\u093E\u0930\u0923\u093E \u092E\u0942\u0930\u094D\u0927\u094D\u0928\u093F \u0938\u0930\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0915\u0930\u0940 \u0938\u094D\u092E\u0943\u0924\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u0942\u0924\u0947\u092D\u094D\u092F\u0903 \u0915\u0948\u0935\u0932\u094D\u092F\u0902 \u091A\u093F\u0924\u094D\u0924\u0938\u094D\u092F \u0924\u0924\u0903 \u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0939\u0930\u0923\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u0928\u093E\u092D\u094D\u092F\u093E\u0902 \u0939\u0943\u0926\u092F\u0938\u091E\u094D\u091A\u093E\u0930\u093E\u0928\u094D\u092E\u0928\u0936\u094D\u091A\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0917\u094B\u091A\u0930\u093E\u0924\u094D\u0964<br> \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0936\u094D\u091A\u0924\u0941\u0930\u094D\u0925\u0938\u094D\u0924\u0941 \u0938\u0941\u092A\u094D\u0930\u0936\u093E\u0928\u094D\u0924 \u0907\u0924\u093F \u0936\u094D\u0930\u0941\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0939\u0943\u0926\u092F\u093E\u0928\u094D\u0928\u093E\u092D\u094C \u092A\u094D\u0930\u093E\u0923\u0938\u094D\u092F \u0935\u093F\u0937\u092F\u0947\u092D\u094D\u092F\u094B \u092E\u0928\u0938\u0936\u094D\u091A \u0924\u0924\u094D\u0930\u0948\u0935 \u0938\u091E\u094D\u091A\u093E\u0930\u0923\u093E\u0926\u093F\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u092D\u0942\u0924\u0947\u092D\u094D\u092F\u0903 \u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u0902 \u0924\u0926\u0928\u0941\u092A\u0930\u0915\u094D\u0924\u0938\u094D\u0935\u091A\u094D\u091B\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u091A\u093F\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u092D\u093F\u0924\u094D\u0924\u094D\u0935\u093E \u0915\u094D\u0930\u092E\u0947\u0923 \u0938\u0930\u094D\u0935\u093E\u0923\u094D\u092F\u0941\u0928\u094D\u092E\u0928\u093E\u0928\u094D\u0924\u093E\u0928\u093F \u092F\u093E\u0928\u093F \u091A\u0964<br> \u092A\u0942\u0930\u094D\u0935\u094B\u0915\u094D\u0924\u0932\u0915\u094D\u0937\u0923\u0948\u0930\u094D\u0926\u0947\u0935\u093F \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0924\u093E\u0902 \u0935\u094D\u0930\u091C\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u0942\u0924\u0938\u0928\u094D\u0927\u093E\u0928\u092D\u0942\u0924\u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u0935\u093F\u0936\u094D\u0935\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0903 (\u0967-\u0968\u0966) \u0907\u0924\u093F \u092F\u0924\u094D\u092A\u0942\u0930\u094D\u0935\u092E\u0941\u0915\u094D\u0924\u0902 \u0924\u091A\u094D\u091B\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F\u0938\u092E\u093E\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u092F\u093E\u092F\u0924\u094D\u0928\u0924\u094B \u092D\u0935\u0924\u093F\u0964 \u0907\u0926\u0902 \u0924\u094D\u0935\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0938\u093E\u0927\u094D\u092F\u092E\u093F\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u096B\u0965</p></div><hr><div class="trans"><p>Eva\u1E41 dhy\u0101n\u0101khyam\u0101\u1E47avamup\u0101ya\u1E41 pradar\u015Bya tadekayogak\u1E63em\u0101n pr\u0101\u1E47\u0101y\u0101madh\u0101ra\u1E47\u0101praty\u0101h\u0101rasam\u0101dh\u012Bn pradar\u015Bayati\u2014</p><blockquote><p><strong>N\u0101\u1E0D\u012Bsa\u1E41h\u0101rabh\u016Btajayabh\u016Btakaivalyabh\u016Btap\u1E5Bthaktv\u0101ni||5||</strong></p></blockquote><p>Yogin\u0101 bh\u0101van\u012By\u0101n\u012Bti \u015Be\u1E63a\u1E25| N\u0101\u1E0D\u012Bn\u0101\u1E41 pr\u0101\u1E47\u0101p\u0101n\u0101div\u0101hin\u012Bn\u0101\u1E41 su\u1E63\u012B\u1E47\u0101\u1E41 sa\u1E41h\u0101ra\u1E25 pr\u0101\u1E47\u0101p\u0101nayukty\u0101ikatrod\u0101navahny\u0101tmani madhyan\u0101\u1E0Dy\u0101\u1E41 vil\u012Bnat\u0101p\u0101danam| Yadukta\u1E41 \u015Br\u012Bmatsvacchande</p><blockquote><p>Apasavyena p\u016Bryeta savyenaiva virecayet|<br> N\u0101\u1E0D\u012Bsa\u1E41\u015Bodhana\u1E41 caitanmok\u1E63am\u0101rgapathasya ca||<br> Recan\u0101tp\u016Bra\u1E47\u0101drodh\u0101tpr\u0101\u1E47\u0101y\u0101mastridh\u0101 sm\u1E5Bta\u1E25|<br> S\u0101m\u0101ny\u0101 bahirete tu puna\u015Bc\u0101bhyantare traya\u1E25||<br> \u0100bhyantare\u1E47a recyeta p\u016Bryet\u0101bhyantare\u1E47a tu|<br> Ni\u1E63kampa\u1E41 kumbhaka\u1E41 k\u1E5Btv\u0101 k\u0101ry\u0101\u015Bc\u0101bhyantar\u0101straya\u1E25||</p></blockquote><p>iti| Bh\u016Bt\u0101n\u0101\u1E41 p\u1E5Bthivy\u0101d\u012Bn\u0101\u1E41 jayo dh\u0101ra\u1E47\u0101bhirva\u015B\u012Bk\u0101ra\u1E25| Yathokta\u1E41 tatraiva</p><blockquote><p>V\u0101yav\u012B dh\u0101ra\u1E47\u0101\u1E45gu\u1E63\u1E6Dha \u0101gney\u012B n\u0101bhimadhyata\u1E25|<br> M\u0101hey\u012B ka\u1E47\u1E6Dhade\u015Be tu v\u0101ru\u1E47\u012B gha\u1E47\u1E6Dik\u0101\u015Bray\u0101||<br> \u0100k\u0101\u015Badh\u0101ra\u1E47\u0101 m\u016Brdhni sarvasiddhikar\u012B sm\u1E5Bt\u0101|</p></blockquote><p>iti| Bh\u016Btebhya\u1E25 kaivalya\u1E41 cittasya tata\u1E25 praty\u0101hara\u1E47am| Yadukta\u1E41 tatraiva</p><blockquote><p>N\u0101bhy\u0101\u1E41 h\u1E5Bdayasa\xF1c\u0101r\u0101nmana\u015Bcendriyagocar\u0101t|<br> Pr\u0101\u1E47\u0101y\u0101ma\u015Bcaturthastu supra\u015B\u0101nta iti \u015Bruta\u1E25||</p></blockquote><p>iti| H\u1E5Bday\u0101nn\u0101bhau pr\u0101\u1E47asya vi\u1E63ayebhyo manasa\u015Bca tatraiva sa\xF1c\u0101ra\u1E47\u0101dityartha\u1E25| Bh\u016Btebhya\u1E25 p\u1E5Bthaktva\u1E41 tadanuparaktasvacchasvacchandacid\u0101tmat\u0101| Yadukta\u1E41 tatraiva</p><blockquote><p>Bhittv\u0101 krame\u1E47a sarv\u0101\u1E47yunman\u0101nt\u0101ni y\u0101ni ca|<br> P\u016Brvoktalak\u1E63a\u1E47airdevi tyaktv\u0101 svacchandat\u0101\u1E41 vrajet||</p></blockquote><p>iti| Bh\u016Btasandh\u0101nabh\u016Btap\u1E5Bthaktvavi\u015Bvasa\u1E45gha\u1E6D\u1E6D\u0101\u1E25 (1-20) iti yatp\u016Brvamukta\u1E41 tacch\u0101mbhavop\u0101yasam\u0101vi\u1E63\u1E6Dasy\u0101yatnato bhavati| Ida\u1E41 tv\u0101\u1E47avop\u0101yaprayatnas\u0101dhyamiti vi\u015Be\u1E63a\u1E25||5||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043F\u043E\u0441\u043B\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F <em>(pradar\u015Bya)</em> \u0101\u1E47ava \u043C\u0435\u0442\u043E\u0434\u0430 --\u0442.\u0435. \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u043A \u0100\u1E47avop\u0101ya-- <em>(\u0101\u1E47avam up\u0101yam)</em>, \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u043E\u0433\u043E <em>(\u0101khyam)</em> dhy\u0101na <em>(dhy\u0101na)</em>, [\u015Aiva \u0442\u0435\u043F\u0435\u0440\u044C] \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 <em>(pradar\u015Bayati)</em> pr\u0101\u1E47\u0101y\u0101ma, dh\u0101ra\u1E47\u0101, praty\u0101h\u0101ra and sam\u0101dhi <em>(pr\u0101\u1E47\u0101y\u0101ma-dh\u0101ra\u1E47\u0101-praty\u0101h\u0101ra-sam\u0101dh\u012Bn)</em><sup>1</sup>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 [\u0443\u0434\u043E\u0431\u043D\u044B] \u0434\u043B\u044F \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044F \u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F <em>(yogak\u1E63em\u0101n)</em> \u044D\u0442\u043E\u0439 [dhy\u0101na] <em>(tad)</em> \u0438\u0441\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(eka)</em>\u2014</p><blockquote><p><strong>[Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u043E\u0441\u0442\u0438\u0447\u044C] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(sa\u1E41h\u0101ra)</em> \u0432 \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(n\u0101\u1E0D\u012B)</em>, \u043F\u043E\u0431\u0435\u0434\u044B \u043D\u0430\u0434 <em>(jaya)</em> \u0433\u0440\u0443\u0431\u044B\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 <em>(bh\u016Bta)</em>, \u043E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u044F [\u0441\u0432\u043E\u0435\u0433\u043E \u0443\u043C\u0430] <em>(kaivalya)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> [\u0438] \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u0438\u044F --p\u1E5Bthaktva-- <em>(p\u1E5Bthaktv\u0101ni)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> [\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0411\u0445\u0430\u0432\u0430\u043D\u044B - Bh\u0101van\u0101, \u0438\u043B\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F \u0442\u0430\u043A\u0436\u0435]||5||</strong></p></blockquote><p>&quot;[\u042D\u0442\u0438 \u043C\u0435\u0442\u043E\u0434\u044B] \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u044B, \u0438\u043B\u0438 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u044B Yog\u012B <em>(yogin\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Bh\u0101van\u0101 --\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F-- <em>(bh\u0101van\u012By\u0101ni)</em>&quot;, \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E [\u043A \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443 \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] <em>(iti \u015Be\u1E63a\u1E25)</em>|</p><p>Sa\u1E41h\u0101ra [\u0430\u043A\u0442 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(sa\u1E41h\u0101ra\u1E25)</em>, \u0442\u0435\u043A\u0443\u0449\u0435\u0439 \u0432 \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(n\u0101\u1E0D\u012Bn\u0101m)</em> [\u0438\u043B\u0438] \u0442\u0440\u0443\u0431\u0430\u0445 --su\u1E63i-- <em>(su\u1E63\u012B\u1E47\u0101m)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044F\u043C\u0438 <em>(v\u0101hin\u012Bn\u0101m)</em> pr\u0101\u1E47a <em>(pr\u0101\u1E47a)</em>, ap\u0101na <em>(ap\u0101na)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F <em>(\u0101p\u0101danam)</em> \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u044D\u0442\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(vil\u012Bnat\u0101)</em> \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435 <em>(ekatra)</em>, \u0442.\u0435. \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u043D\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 <em>(madhya- n\u0101\u1E0Dy\u0101m)</em> \u2014\u0430 \u0438\u043C\u0435\u043D\u043D\u043E [\u0432 \u0421\u0443\u0448\u0443\u043C\u043D\u0435 - Su\u1E63umn\u0101], \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tmani)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0433\u043E\u043D\u044C <em>(vahni)</em> \u0423\u0434\u0430\u043D\u044B (ud\u0101na) <em>(ud\u0101na)</em>\u2014, \u0441 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> \u041F\u0440\u0430\u043D\u044B (pr\u0101\u1E47a) \u0438 \u0410\u043F\u0430\u043D\u044B (ap\u0101na) <em>(pr\u0101\u1E47a-ap\u0101na)</em><sup>2</sup>|</p><p>\u041E\u0431 \u044D\u0442\u043E\u043C <em>(yad)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012Bmat-svacchande)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(p\u016Bryeta)</em> \u0447\u0435\u0440\u0435\u0437 \u043B\u0435\u0432\u0443\u044E [\u043D\u043E\u0437\u0434\u0440\u044E] <em>(apasavyena)</em> [\u0438] \u0432\u044B\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(virecayet)</em> \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0430\u0432\u0443\u044E [\u043D\u043E\u0437\u0434\u0440\u044E] <em>(savyena eva)</em><sup>3</sup>. \u042D\u0442\u043E <em>(etad)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u043B\u043D\u044B\u043C \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435\u043C <em>(sa\u1E41\u015Bodhanam)</em> \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u043E\u0432 <em>(n\u0101\u1E0D\u012B)</em> \u0438 <em>(ca.. ca)</em> \u043F\u0443\u0442\u0438 <em>(m\u0101rga-pathasya)</em> \u043A \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E <em>(mok\u1E63a)</em> --\u0442.\u0435. Su\u1E63umn\u0101--. \u0418\u0437-\u0437\u0430 \u0430\u043A\u0442\u043E\u0432 \u0432\u044B\u0434\u043E\u0445\u0430 <em>(recan\u0101t)</em>, \u0432\u0434\u043E\u0445\u0430 <em>(p\u016Bra\u1E47\u0101t)</em> [\u0438] \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 --\u0442.\u0435. \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0438-- <em>(rodh\u0101t)</em> [\u0434\u044B\u0445\u0430\u043D\u0438\u044F], \u041F\u0440\u0430\u043D\u0430\u044F\u043C\u0430 (pr\u0101\u1E47\u0101y\u0101ma) <em>(pr\u0101\u1E47a-\u0101y\u0101ma\u1E25)</em> \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(sm\u1E5Bta\u1E25)</em> \u0442\u0440\u043E\u0439\u043D\u043E\u0439 <em>(tridh\u0101)</em>. \u042D\u0442\u0438 [\u0442\u0440\u0438 pr\u0101\u1E47\u0101y\u0101ma-s] <em>(ete)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(tu)</em> \u043E\u0431\u044B\u0447\u043D\u044B\u043C\u0438 <em>(s\u0101m\u0101ny\u0101\u1E25)</em> [\u0438] \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 --\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u044B\u0445\u0430\u043D\u0438\u0435 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F \u0432\u043E\u0432\u043D\u0435, \u0430 \u043D\u0435 \u0432\u043D\u0443\u0442\u0440\u0438 \u0442\u0435\u043B\u0430, \u043F\u043E\u0441\u043B\u0435 \u0432\u044B\u0434\u043E\u0445\u0430-- <em>(bahis)</em>. \u041E\u0434\u043D\u0430\u043A\u043E <em>(punar ca)</em>, [\u0438\u043C\u0435\u044E\u0442\u0441\u044F] \u0442\u0440\u0438 <em>(traya\u1E25)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C\u0438 --\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u044B\u0445\u0430\u043D\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438, \u0430 \u043D\u0435 \u0432\u043E\u0432\u043D\u0435 \u0442\u0435\u043B\u0430, \u043F\u043E\u0441\u043B\u0435 \u0432\u0434\u043E\u0445\u0430-- <em>(\u0101bhyantare)</em>. \u042D\u0442\u0438 \u0442\u0440\u0438 <em>(traya\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 [pr\u0101\u1E47\u0101y\u0101ma-s] <em>(\u0101bhyantar\u0101\u1E25)</em> \u0434\u043E\u043B\u0436\u043D\u044B \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F <em>(k\u0101ry\u0101\u1E25 ca)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:] \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u041F\u0440\u0430\u043D\u0430\u044F\u043C\u044B [pr\u0101\u1E47\u0101y\u0101ma] <em>(\u0101bhyantare\u1E47a)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(recyeta)</em> [\u0438] \u0447\u0435\u0440\u0435\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0436\u0435 \u041F\u0440\u0430\u043D\u0430\u044F\u043C\u0443 <em>(\u0101bhyantare\u1E47a)</em> \u0432\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(p\u016Bryeta)</em> \u0442\u0430\u043A\u0436\u0435 <em>(tu)</em>. [\u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u0447\u0435\u0440\u0435\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u041F\u0440\u0430\u043D\u0430\u044F\u043C\u0443] \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F --\u0431\u0443\u043A\u0432. \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F-- <em>(k\u1E5Btv\u0101)</em> \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0430\u044F <em>(ni\u1E63kampam)</em> \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0430 \u0434\u044B\u0445\u0430\u043D\u0438\u044F <em>(kumbhakam... iti)</em>&quot;||<br> [\u0421\u043C. \u0441\u0442\u0440\u043E\u0444\u044B 294-297 \u0432 7-\u043C pa\u1E6Dala Svacchandatantra]</p></blockquote><p>\u041F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u0435 <em>(jaya\u1E25)</em> \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bt\u0101n\u0101m)</em> [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u0437\u0435\u043C\u043B\u044F \u0438 \u0442.\u043F. <em>(p\u1E5Bthiv\u012B-\u0101d\u012Bn\u0101m)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043B\u0430\u0441\u0442\u044C\u044E, \u0438\u043B\u0438 \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E\u043C [\u043D\u0430\u0434 \u043D\u0438\u043C\u0438] <em>(va\u015B\u012Bk\u0101ra\u1E25)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438, \u0438\u043B\u0438 dh\u0101ra\u1E47\u0101-s <em>(dh\u0101ra\u1E47\u0101bhi\u1E25)</em><sup>4</sup>|</p><p>\u041A\u0430\u043A \u0443\u0436\u0435 \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(yath\u0101 uktam)</em> \u0432 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C [Svacchandatantra] <em>(tatra eva)</em>:</p><blockquote><p>&quot;\u041E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0432\u043E\u0437\u0434\u0443\u0445\u0443 <em>(v\u0101yav\u012B)</em> \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em> \u043D\u0430 \u0431\u043E\u043B\u044C\u0448\u043E\u043C \u043F\u0430\u043B\u044C\u0446\u0435 \u043D\u043E\u0433\u0438 <em>(a\u1E45gu\u1E63\u1E6Dhe)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u043E\u0433\u043D\u044E <em>(\u0101grey\u012B)</em> \u2014 \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhyatas)</em> \u043F\u0443\u043F\u043A\u0430 <em>(n\u0101bhi)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0437\u0435\u043C\u043B\u0435 <em>(m\u0101hey\u012B)</em> \u2014 \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 <em>(de\u015Be)</em> \u0433\u043E\u0440\u043B\u0430 <em>(ka\u1E47\u1E6Dha... tu)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0432\u043E\u0434\u0435 [\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F] <em>(v\u0101ru\u1E47\u012B)</em> \u0441 \u043E\u043F\u043E\u0440\u043E\u0439 --\u0442.\u0435. \u043E\u043F\u043E\u0440\u043E\u0439, \u0438\u043B\u0438 \u0444\u043E\u043A\u0443\u0441\u043E\u043C \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438-- <em>(\u0101\u015Bray\u0101)</em> \u043D\u0430 \u044F\u0437\u044B\u0447\u043A\u0435 <em>(gha\u1E47\u1E6Dik\u0101)</em>, [\u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446,] \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u044D\u0444\u0438\u0440\u0443, \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0443 <em>(\u0101k\u0101\u015Ba)</em> \u2014 \u043D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0435 \u0433\u043E\u043B\u043E\u0432\u044B <em>(m\u016Brdhni)</em>. [\u042D\u0442\u0438 \u0432\u0438\u0434\u044B \u0441\u043E\u0441\u0442\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u044F], \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(sm\u1E5Bt\u0101)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442 <em>(kar\u012B)</em> \u0432\u0441\u0435 <em>(sarva)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B <em>(siddhi... iti)</em><sup>5</sup>&quot;|<br> [\u0421\u043C. \u0441\u0442\u0440\u043E\u0444\u044B 299-300 \u0432 7-\u043C pa\u1E6Dala Svacchandatantra]</p></blockquote><p>\u041E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u0435 <em>(kaivalyam)</em> \u0443\u043C\u0430 <em>(cittasya)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Btebhya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas)</em> praty\u0101h\u0101ra <em>(praty\u0101hara\u1E47am)</em>|</p><p>\u041E\u0431 \u044D\u0442\u043E\u043C <em>(yad)</em> \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0443\u0435\u0442 <em>(uktam)</em> \u0438 [Svacchandatantra] <em>(tatra eva)</em>:</p><blockquote><p>&quot;[\u0417\u0430\u0434\u0435\u0440\u0436\u043A\u0430 \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0432 \u043F\u0443\u043F\u043A\u0435, \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u043C\u044B\u0435 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E,] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0435\u0440\u0435\u043D\u043E\u0441\u0430 [\u0435\u0435] <em>(sa\xF1c\u0101r\u0101t)</em> \u043E\u0442 \u0441\u0435\u0440\u0434\u0446\u0430 <em>(h\u1E5Bdaya)</em> \u043A \u043F\u0443\u043F\u043A\u0443 <em>(n\u0101bhy\u0101m)</em>, \u0438 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> [\u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C] \u0443\u043C\u0430 <em>(manas)</em> [\u0432 \u043F\u0443\u043F\u043A\u0435 \u0447\u0435\u0440\u0435\u0437 \u0435\u0433\u043E \u043E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u0435] \u043E\u0442 \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 [\u043A \u043F\u0443\u043F\u043A\u0443] <em>(indriya-gocar\u0101t)</em>, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F <em>(caturtha\u1E25)</em> pr\u0101\u1E47\u0101y\u0101ma <em>(pr\u0101\u1E47\u0101y\u0101ma\u1E25)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A] \u043E\u0447\u0435\u043D\u044C \u0443\u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0448\u0435\u043D\u043D\u0430\u044F, \u0438\u043B\u0438 \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u0430\u044F <em>(supra\u015B\u0101nta\u1E25)</em>, [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 <em>(tu)</em>. \u042D\u0442\u043E \u0442\u043E, \u0447\u0435\u043C\u0443 \u0443\u0447\u0438\u043B\u0438 <em>(iti \u015Bruta\u1E25... iti)</em><sup>6</sup>&quot;||<br> [\u0421\u043C. \u0441\u0442\u0440\u043E\u0444\u044B 297 \u0432 7-\u043C pa\u1E6Dala Svacchandatantra]</p></blockquote><p>\u0427\u0435\u0440\u0435\u0437 \u043F\u0435\u0440\u0435\u043D\u043E\u0441 <em>(sa\xF1c\u0101ra\u1E47\u0101t)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47asya)</em> \u043E\u0442 \u0441\u0435\u0440\u0434\u0446\u0430 <em>(h\u1E5Bday\u0101t)</em> \u043A \u043F\u0443\u043F\u043A\u0443 <em>(n\u0101bhau)</em>, \u0438 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> [\u0447\u0435\u0440\u0435\u0437 \u043F\u0435\u0440\u0435\u043D\u043E\u0441] \u0443\u043C\u0430 <em>(manasa\u1E25)</em> \u0432 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u0435\u0433\u043E --\u0442.\u0435. \u043F\u0443\u043F\u043A\u0430-- <em>(tatra eva)</em> \u043E\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(vi\u1E63ayebhya\u1E25)</em> [\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C praty\u0101h\u0101ra, \u0438\u043B\u0438 \u043E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u044F \u0443\u043C\u0430]. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>\u041E\u0442\u0434\u0435\u043B\u0435\u043D\u0438\u0435 <em>(p\u1E5Bthaktva)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Btebhya\u1E25)</em> [\u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442] \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(\u0101tmat\u0101)</em> \u0447\u0438\u0441\u0442\u043E\u0433\u043E <em>(svaccha)</em> [\u0438] \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E <em>(svacchanda)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0442.\u0435. \u015Aiva-- <em>(cit)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0435 \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u043E <em>(anuparakta)</em> \u0438\u043C\u0438 --\u0442.\u0435. \u0433\u0440\u0443\u0431\u044B\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438-- <em>(tad)</em>|</p><p>\u042D\u0442\u043E \u0436\u0435 <em>(yad)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C [Svacchandatantra] <em>(tatra eva)</em>:</p><blockquote><p>&quot;\u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>! \u041F\u043E\u0441\u043B\u0435 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u043D\u0438\u044F <em>(bhittv\u0101 krame\u1E47a)</em> \u0432\u0441\u0435\u0445 [\u0443\u0437\u043B\u043E\u0432 --\u0432 \u0441\u0435\u0440\u0434\u0446\u0435, \u0433\u043E\u0440\u043B\u0435 \u0438 \u0442.\u0434.--] <em>(sarv\u0101\u1E47i)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(y\u0101ni ca)</em> \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F <em>(ant\u0101ni)</em> \u0432 Unman\u0101 <em>(unman\u0101)</em>, \u0447\u0435\u0440\u0435\u0437 \u043E\u043F\u044B\u0442/\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F --\u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043C\u0435\u0442\u043E\u0434\u043E\u0432-- <em>(lak\u1E63a\u1E47ai\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u043E\u043F\u0438\u0441\u0430\u043D\u044B \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brva-ukta)</em> [\u0432 \u0448\u0435\u0441\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435, \u0438\u043B\u0438 pa\u1E6Dala Svacchandatantra]; \u0447\u0435\u0440\u0435\u0437 \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 <em>(tyaktv\u0101)</em> [\u0432\u0441\u0435\u0433\u043E \u044D\u0442\u043E\u0433\u043E, Yog\u012B] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(vrajet)</em> [\u0412\u044B\u0441\u0448\u0435\u0439] \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(svacchandat\u0101m... iti)</em><sup>7</sup>&quot;|<br> [\u0421\u043C. \u0441\u0442\u0440\u043E\u0444\u0443 327 \u0432 7-\u043C pa\u1E6Dala Svacchandatantra]</p></blockquote><p>\u0422\u043E <em>(tad)</em>, \u0447\u0442\u043E <em>(yad)</em> \u0440\u0430\u043D\u0435\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C <em>(p\u016Brvam uktam)</em> \u0432 I, 20 [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-20)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E: &quot;[\u0414\u0440\u0443\u0433\u0438\u0435 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B \u2014 \u044D\u0442\u043E \u0441\u0438\u043B\u0430] \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sandh\u0101na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(bh\u016Bta)</em>; [\u0441\u0438\u043B\u0430] \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F <em>(p\u1E5Bthaktva)</em> \u0438\u0445 \u0432\u0441\u0435\u0445 --\u0442.\u0435. \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432-- <em>(bh\u016Bta)</em> [\u0438 \u0441\u0438\u043B\u0430] \u0441\u043E\u0431\u0438\u0440\u0430\u043D\u0438\u044F --sa\u1E45gha\u1E6D\u1E6Da-- <em>(sa\u1E45gha\u1E6D\u1E6D\u0101\u1E25)</em> \u0432\u0441\u0435\u0433\u043E <em>(vi\u015Bva... iti)</em>, [\u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C \u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C]&quot;, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0431\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u0439 <em>(ayatnatas)</em> \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0432\u043E\u0448\u0435\u043B <em>(sam\u0101vi\u1E63tasya)</em> \u0432 \u015A\u0101mbhavop\u0101ya --\u043C\u0435\u0442\u043E\u0434\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0435\u0441\u044F \u043A \u015Aiva-- <em>(\u015B\u0101mbhava-up\u0101ya)</em>|</p><p>\u041D\u043E <em>(tu)</em> \u044D\u0442\u043E --\u0442.\u0435. \u0442\u043E, \u0447\u0442\u043E \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 I, 20-- <em>(idam)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E <em>(s\u0101dhyam)</em> \u0447\u0435\u0440\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u044F <em>(prayatna)</em> \u0432 \u0100\u1E47avop\u0101ya --\u043C\u0435\u0442\u043E\u0434\u0430\u043C\u0438, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u043C\u0441\u044F \u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043C-- <em>(\u0101\u1E47ava-up\u0101ya)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(iti vi\u015Be\u1E63a\u1E25)</em>||5||</p><hr><ol><li>\u042D\u0442\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u044B \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0442\u0430\u043A\u0436\u0435, \u043A\u0430\u043A \u043E\u043D\u0438 \u0431\u044B\u043B\u0438 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u044B \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C Pata\xF1jali \u0432 \u0435\u0433\u043E Yogas\u016Btra-s II, 49 (pr\u0101\u1E47\u0101y\u0101ma) - III, 1 (dh\u0101ra\u1E47\u0101) - II, 54 (praty\u0101h\u0101ra)</li></ol><ul><li>III, 3 (sam\u0101dhi), \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0432\u0441\u044E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u0443\u044E \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E, \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044D\u0442\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u044B \u043D\u0430 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0435, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0439 \u0432\u0441\u0435 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0435 s\u016Btra-s, \u0442.\u0435. P\u0101ta\xF1jalayogas\u016Btra-s, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0442\u043E, \u0447\u0442\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 A\u1E63\u1E6D\u0101\u1E45gayoga.</li></ul><ol start="2"><li><p>\u041C\u0435\u0442\u043E\u0434 pr\u0101\u1E47a (\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u0441 \u0432\u044B\u0434\u043E\u0445\u043E\u043C) \u0438 ap\u0101na (\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0432\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u043D\u0430 \u0432\u0434\u043E\u0445\u0435) \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0441\u0442\u043E \u0432 \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0435 \u0434\u044B\u0445\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 \u043A Su\u1E63umn\u0101 (\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u043D\u043E\u043C\u0443, \u0438\u043B\u0438 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u043C\u0443 \u043A\u0430\u043D\u0430\u043B\u0443). \u041A\u043E\u0433\u0434\u0430 pr\u0101\u1E47a \u0438 ap\u0101na \u0441\u0442\u0430\u0431\u0438\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u0432 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435, \u044D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F sam\u0101na. \u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u044D\u0442\u0430 sam\u0101na \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F \u0432 ud\u0101na, \u043E\u0442\u0441\u044E\u0434\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u043E\u0431\u0440\u0430\u0437\u043D\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u043E\u0433\u043D\u0435\u043C&quot;. \u041D\u0443, \u0447\u0442\u043E \u0436, \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044D\u0442\u0438 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u044B, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430, \u0442\u043E\u0433\u0434\u0430 \u043C\u043D\u0435 \u043D\u0435 \u043D\u0430\u0434\u043E \u043F\u0438\u0441\u0430\u0442\u044C \u0434\u043B\u0438\u043D\u043D\u044B\u0445 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0439.</p></li><li><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E &quot;savya&quot; \u0438 &quot;apasavya&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E &quot;\u043B\u0435\u0432\u044B\u0439&quot; \u0438 &quot;\u043F\u0440\u0430\u0432\u044B\u0439&quot; \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u044F \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u043B &quot;savyena&quot; \u0438 &quot;apasvyena&quot; \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A K\u1E63emar\u0101ja \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0432 \u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A Svacchandatantra, \u0442.\u0435. \u043A\u0430\u043A \u043D\u0435\u0441\u043A\u043B\u043E\u043D\u044F\u0435\u043C\u044B\u0435 &quot;\u0441\u043F\u0440\u0430\u0432\u0430&quot; \u0438 &quot;\u0441\u043B\u0435\u0432\u0430&quot;. \u041E\u043D \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 VII, 294 \u0432 Svacchandatantra \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C: &quot;\u0938\u0935\u094D\u092F\u0947\u0928 \u0926\u0915\u094D\u0937\u0928\u093E\u0938\u093E\u092A\u0925\u0947\u0928 \u0930\u0947\u091A\u092F\u0947\u0926\u094D\u0930\u0947\u091A\u0915\u0902 \u0915\u0941\u0930\u094D\u092F\u093E\u0926\u092A\u0938\u0935\u094D\u092F\u0947\u0928 \u0935\u093E\u092E\u0947\u0928 \u092A\u0942\u0930\u094D\u092F\u0947\u0924 \u0935\u093E\u092F\u0941\u092A\u0942\u0930\u0923\u0902 \u0915\u0941\u0930\u094D\u092F\u093E\u0926\u093F\u0924\u094D\u092F\u0930\u094D\u0925\u0903 &quot; - &quot;Savyena dak\u1E63an\u0101s\u0101pathena recayedrecaka\u1E41 kury\u0101dapasavyena v\u0101mena p\u016Bryeta v\u0101yup\u016Bra\u1E47a\u1E41 kury\u0101dityartha\u1E25&quot; - &quot;\u041E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u0434\u043E\u0445\u043D\u0443\u0442\u044C \u2014\u0442.\u0435. \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0430\u043A\u0442 \u0432\u044B\u0434\u043E\u0445\u0430\u2014 \u0447\u0435\u0440\u0435\u0437 savya \u2014\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0430\u0432\u0443\u044E \u043D\u043E\u0437\u0434\u0440\u044E\u2014; [\u0438] \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0434\u043E\u0445\u043D\u0443\u0442\u044C \u2014\u0442.\u0435. \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043D\u0430\u043F\u043E\u043B\u043D\u0438\u0442\u044C\u0441\u044F \u0432\u043E\u0437\u0434\u0443\u0445\u043E\u043C\u2014 \u0447\u0435\u0440\u0435\u0437 apasavya \u2014\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u043B\u0435\u0432\u0443\u044E [\u043D\u043E\u0437\u0434\u0440\u044E]\u2014. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435&quot;. \u0418\u0442\u0430\u043A, \u0442\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u043D\u043E?</p></li></ol><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044F \u0443\u0432\u0438\u0434\u0435\u043B \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0435 \u043D\u0435\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F \u043C\u0435\u0436\u0434\u0443 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C\u0438 \u0437\u0434\u0435\u0441\u044C \u0441\u0442\u0440\u043E\u0444\u0430\u043C\u0438 \u0438 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u0438\u0437 Svacchandatantra (\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u043F\u0435\u0447\u0430\u0442\u043A\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u0435\u0440\u0435\u043F\u0438\u0441\u044B\u0432\u0430\u043D\u0438\u044F), \u044F \u043F\u0440\u0438\u043D\u044F\u043B \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E \u0432\u043D\u0435\u0441\u0442\u0438 \u044D\u0442\u0438 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u0440\u043E\u0444\u044B \u0438\u0437 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0433\u043E Svacchandatantra \u0432 \u0442\u0435\u043A\u0441\u0442 \u015Aivas\u016Btravimar\u015Bin\u012B \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u0438\u0441\u043F\u0440\u0430\u0432\u0438\u0442\u044C \u0432\u0441\u0435 \u043E\u0448\u0438\u0431\u043A\u0438. \u042F \u0441\u0443\u043C\u0430\u0441\u0448\u0435\u0434\u0448\u0438\u0439? \u0414\u0430, \u043F\u043E \u043A\u0440\u0430\u0439\u043D\u0435\u0439 \u043C\u0435\u0440\u0435, \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E! \u042D\u0442\u0438 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u044B, \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F \u043C\u043E\u0433\u0443\u0442 \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u0435\u0441\u0442\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0441 \u0443\u043C\u0430, \u0431\u0443\u0434\u044C\u0442\u0435 \u0443\u0432\u0435\u0440\u0435\u043D\u044B, \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0438\u0445 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0442\u0440\u0443\u0434\u043D\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C, \u0438 \u043C\u043E\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0430\u0441\u0430\u043C\u0438 \u043D\u0430 \u0432\u0441\u0435 100%, \u043D\u043E \u0438 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043F\u043E\u043C\u0438\u043C\u043E \u0443\u0447\u0435\u043D\u0438\u044F, \u0442\u0435\u043A\u0441\u0442 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u043E\u0448\u0435\u043B\u043E\u043C\u043B\u044F\u044E\u0449\u0443\u044E \u0441\u0438\u043B\u0443, \u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0438\u0437 \u0441\u0430\u043C\u0438\u0445 \u0441\u0438\u043C\u0432\u043E\u043B\u043E\u0432. \u042F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043E\u043F\u0438\u0441\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u043E\u043F\u044B\u0442 \u0441\u043B\u043E\u0432\u0430\u043C\u0438. \u042D\u0442\u043E \u043A\u0430\u043A \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u0432 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u0447\u0435\u0433\u043E-\u0442\u043E \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0438\u0441\u0446\u0435\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0438 \u0440\u0430\u0434\u0438\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0432 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0432\u0440\u0435\u043C\u044F. \u041B\u044E\u0434\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u044F\u0442, \u0447\u0442\u043E \u043E\u043D\u0438 \u0438\u0449\u0443\u0442 \u0411\u043E\u0433\u0430 (\u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439), \u043F\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u043C\u043D\u0435, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445 \u043D\u0435 \u0437\u043D\u0430\u044E\u0442, \u043E \u0447\u0435\u043C \u043E\u043D\u0438 \u0433\u043E\u0432\u043E\u0440\u044F\u0442. \u0415\u0441\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u043A\u0430\u043A \u0442\u0430\u043A\u043E\u0432\u043E\u0435 (\u0442.\u0435. \u0431\u0435\u0437 \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438, \u0431\u0435\u0437 \u043A\u0430\u043A\u043E\u0439-\u043B\u0438\u0431\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u043A\u0438/\u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F, \u0438 \u0442.\u043F.), \u043D\u0430\u0439\u0434\u0435\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0438 \u0415\u0433\u043E \u0421\u0438\u043B\u0443, \u0435\u0433\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E \u043D\u0435 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0435\u0442 \u044D\u0442\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430. \u0412\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u043E, \u0447\u0442\u043E \u043E\u043D\u043E \u0443\u0431\u0438\u0432\u0430\u0435\u0442 \u0432\u0430\u0448\u0443 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0434\u043E \u0441\u0430\u043C\u044B\u0445 \u043A\u043E\u0440\u043D\u0435\u0439! \u0412\u0441\u0435 \u044D\u0442\u0438 \u0442\u0435\u043A\u0441\u0442\u044B, \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u043C\u044B\u0435 \u043C\u043D\u043E\u0439, \u0431\u044B\u043B\u0438 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u044B \u0418\u043C \u0421\u0430\u043C\u0438\u043C \u0438 \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u044B \u0432\u0435\u043B\u0438\u043A\u0438\u043C\u0438 \u043C\u0443\u0434\u0440\u0435\u0446\u0430\u043C\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043E\u043D\u0438 \u043F\u043E\u043B\u043D\u044B \u0415\u0433\u043E \u0421\u0438\u043B\u044B \u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0442\u0430\u0439\u043D. \u041A\u043E\u0433\u0434\u0430 \u043A\u0442\u043E-\u0442\u043E \u043F\u0440\u0438\u0431\u043B\u0438\u0436\u0430\u0435\u0442\u0441\u044F \u043A \u043D\u0438\u043C, \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u043E\u0447\u0435\u043D\u044C \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u043D\u044B\u043C \u0438 \u0443\u0432\u0430\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C.</p><ol start="4"><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;dh\u0101ra\u1E47\u0101&quot; (\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F) \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u043D \u0437\u0434\u0435\u0441\u044C \u0442\u0430\u043A \u0436\u0435, \u043A\u0430\u043A \u0435\u0433\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 \u043C\u0443\u0434\u0440\u0435\u0446 Pata\xF1jali \u0432 \u0441\u0432\u043E\u0438\u0445 Yogas\u016Btra-s (III, 1).</p></li><li><p>K\u1E63emar\u0101ja \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u0438 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u0444\u044B Svacchandatantra, \u0434\u0430\u0432\u0430\u044F \u0442\u043E\u0447\u043D\u044B\u0439 \u043C\u0435\u0442\u043E\u0434, \u043A\u0430\u043A \u0438\u0445 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044E \u043D\u0435 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0438\u0437\u0443\u0447\u0430\u0442\u044C \u0438\u0445, \u0447\u0442\u043E\u0431\u044B \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0432\u0441\u0435 \u044D\u0442\u0438 \u0441\u0432\u0435\u0440\u0445\u0441\u0438\u043B\u044B \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435! \u041C\u043E\u0439 \u0411\u043E\u0433, \u0442\u044B \u043D\u0435 \u0437\u0430\u0445\u043E\u0447\u0435\u0448\u044C \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u044D\u0442\u0438 \u0441\u0432\u0435\u0440\u0445\u0441\u0438\u043B\u044B, \u0431\u0443\u0434\u044C \u0443\u0432\u0435\u0440\u0435\u043D. \u041A\u0430\u043A \u043E\u0442\u043C\u0435\u0447\u0430\u0435\u0442 \u0432\u044B\u0434\u0430\u044E\u0449\u0438\u0439\u0441\u044F \u043C\u0443\u0434\u0440\u0435\u0446 Pata\xF1jali \u0432 \u0441\u0432\u043E\u0438\u0445 \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0445 Yogas\u016Btra-s (III, 37):</p></li></ol><blockquote><p>&quot;\u0924\u0947 \u0938\u092E\u093E\u0927\u093E\u0935\u0941\u092A\u0938\u0930\u094D\u0917\u093E \u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u0938\u093F\u0926\u094D\u0927\u092F\u0903&quot; - &quot;Te sam\u0101dh\u0101vupasarg\u0101 vyutth\u0101ne siddhaya\u1E25&quot; - &quot;\u042D\u0442\u0438 [\u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0435\u043C, \u0438\u043B\u0438 \u043F\u043E\u043C\u0435\u0445\u043E\u0439 \u0432 Sam\u0101dhi, [\u043D\u043E] \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F\u043C\u0438 \u0432 Vyutth\u0101na --\u0442.\u0435. \u043E\u0431\u044B\u0447\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0443\u043C \u043D\u0435\u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432 (\u043A\u043E\u043B\u0435\u0431\u043B\u0435\u0442\u0441\u044F)--&quot;.</p></blockquote><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0445\u043E\u0442\u044F \u044D\u0442\u0438 \u0441\u0432\u0435\u0440\u0445\u0441\u0438\u043B\u044B \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435\u043C \u0434\u043B\u044F \u043A\u043E\u0433\u043E-\u0442\u043E, \u0447\u044C\u0435\u0439 \u0446\u0435\u043B\u044C\u044E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u043E\u0431\u044B\u0447\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0443\u043C \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442, \u043D\u043E \u0434\u043B\u044F \u0442\u0435\u0445, \u043A\u0442\u043E \u0445\u043E\u0447\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0442\u044C \u0432 \u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0439 \u041A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 (Sam\u0101dhi) \u0438, \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u043E\u043D\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u043E\u043A\u043B\u044F\u0442\u0438\u0435\u043C.</p><p>OK, \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u043C\u0441\u044F \u043A \u0442\u0435\u043C\u0435. \u041F\u0435\u0440\u0432\u044B\u0439 \u0430\u0431\u0437\u0430\u0446 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F K\u1E63emar\u0101ja \u043D\u0430 \u044D\u0442\u0438 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u0444\u044B Svacchandatantra \u0441\u0434\u0435\u043B\u0430\u044E\u0442 \u043C\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u043D\u044F\u0442\u043D\u044B\u043C, \u044F \u043D\u0430\u0434\u0435\u044E\u0441\u044C:</p><blockquote><p>&quot;\u092A\u093E\u0926\u0926\u0947\u0936\u0947 \u0924\u093F\u0930\u094D\u092F\u0917\u094D\u0917\u0924\u0947\u0903 \u0928\u093E\u092D\u094C \u091C\u093E\u0920\u0930\u093E\u0917\u094D\u0928\u0947\u0903 \u0915\u0923\u094D\u0920\u0947 \u0938\u094D\u0925\u093F\u0924\u093F\u092A\u0926\u0947 \u0927\u0930\u0923\u094D\u092F\u093E \u0918\u0923\u094D\u091F\u093F\u0915\u093E\u092F\u093E\u0902 \u0930\u0938\u0938\u094D\u092F \u092C\u094D\u0930\u0939\u094D\u092E\u0930\u0928\u094D\u0927\u094D\u0930\u0947 \u091A \u0935\u094D\u092F\u094B\u092E\u094D\u0928\u0903 \u0938\u0926\u094D\u092D\u093E\u0935\u093E\u0924\u094D\u0924\u0925\u0948\u0935 \u0927\u093E\u0930\u0923\u093E \u0909\u0915\u094D\u0924\u093E\u0903\u0964&quot; - &quot;P\u0101dade\u015Be tiryaggate\u1E25 n\u0101bhau j\u0101\u1E6Dhar\u0101gne\u1E25 ka\u1E47\u1E6Dhe sthitipade dhara\u1E47y\u0101 gha\u1E47\u1E6Dik\u0101y\u0101\u1E41 rasasya brahmarandhre ca vyomna\u1E25 sadbh\u0101v\u0101ttathaiva dh\u0101ra\u1E47\u0101 ukt\u0101\u1E25|&quot; - &quot;\u041A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 \u043E\u043F\u0438\u0441\u0430\u043D\u044B [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:] \u041D\u0430 \u0442\u043E\u043C, \u0447\u0442\u043E \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0433\u043E\u0440\u0438\u0437\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u043E --\u044D\u043F\u0438\u0442\u0435\u0442 \u0432\u043E\u0437\u0434\u0443\u0445\u0430-- \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u0441\u0442\u043E\u043F\u044B; \u043D\u0430 \u043E\u0433\u043D\u0435 \u0432 \u0431\u0440\u044E\u0448\u043E\u0439 \u043F\u043E\u043B\u043E\u0441\u0442\u0438 - \u0432 \u043F\u0443\u043F\u043A\u0435; \u043D\u0430 \u0437\u0435\u043C\u043B\u0435 \u2014\u0447\u044C\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u2014\u0432 \u0433\u043E\u0440\u043B\u0435; \u043D\u0430 \u0432\u043E\u0434\u0435 \u2014 \u0432 \u044F\u0437\u044B\u0447\u043A\u0435; \u0438, \u0442\u0430\u043A\u0436\u0435, \u043D\u0430 \u044D\u0444\u0438\u0440\u0435, \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u2014\u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0430\u0448\u0438\u043C \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C \u0411\u044B\u0442\u0438\u0435\u043C\u2014\u0432 Brahmarandhra --\u0442.\u0435. \u0432 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u043C \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0438 Sahasr\u0101racakra, \u043D\u0430 \u0432\u0435\u0440\u0445\u0443\u0448\u043A\u0435 \u0433\u043E\u043B\u043E\u0432\u044B--&quot;.</p></blockquote><p>\u041E, \u0445\u043E\u0440\u043E\u0448\u043E, \u0442\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u0442\u0430\u043A \u0432\u0435\u0434\u044C? \u0415\u0441\u043B\u0438 \u0432\u044B \u043E\u0436\u0438\u0434\u0430\u043B\u0438 \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0441\u043B\u043E\u0432\u0430 \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0438, \u0442\u043E \u0432\u044B \u2014 \u0435\u0449\u0435 \u0431\u043E\u043B\u0435\u0435 \u0441\u0443\u043C\u0430\u0441\u0448\u0435\u0434\u0448\u0438\u0439, \u0447\u0435\u043C \u044F, \u0445\u0430-\u0445\u0430. \u041D\u0435 \u0432\u043E\u043B\u043D\u0443\u0439\u0442\u0435\u0441\u044C, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0432\u0435\u0440\u043D\u044B\u0439. \u041F\u0440\u043E\u0441\u0442\u043E \u0434\u043E\u0432\u0435\u0440\u044F\u0439\u0442\u0435 \u043C\u043D\u0435 \u0442\u043E\u0433\u0434\u0430. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u044D\u0442\u043E \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0441\u043B\u043E\u0432\u0430\u0440\u044F, \u0435\u0441\u043B\u0438 \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u044B \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442\u0435 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u043C\u0438 \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430. \u041F\u043E\u0441\u043B\u043E\u0432\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448, \u043D\u043E \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442 \u0442\u0430\u043A \u043C\u043D\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0442\u0430\u043A\u0436\u0435. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043D\u0435 \u0432\u043A\u043B\u044E\u0447\u0430\u044E \u0435\u0433\u043E \u0432 \u043F\u043E\u044F\u0441\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0437\u0430\u043C\u0435\u0442\u043A\u0438.</p><p>\u0420\u0430\u0437\u0443\u043C\u0435\u0435\u0442\u0441\u044F, \u0432\u043E\u0437\u0434\u0443\u0445, \u043E\u0433\u043E\u043D\u044C, \u0437\u0435\u043C\u043B\u044F, \u0432\u043E\u0434\u0430 \u0438 \u044D\u0444\u0438\u0440/\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C\u0438 \u041C\u0430\u0445\u0430\u0431\u0445\u0443\u0442\u0430\u043C\u0438 (Mah\u0101bh\u016Bta-s) (\u0431\u0443\u043A\u0432. \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B, \u0442.\u0435. \u0433\u0440\u0443\u0431\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B), \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u0441 32-\u0439 \u043F\u043E 36-\u044E \u0432 \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0422\u0440\u0438\u043A\u0438.</p><ol><li>\u041D\u0443 \u0447\u0442\u043E \u0436, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 Svacchandatantra \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u0430\u043C \u043D\u0430\u0434\u043E \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0442\u044C &quot;\u0432\u0435\u0441\u044C&quot; \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438 \u043D\u0430 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443. \u0422\u0435\u043C\u0430 \u044D\u0442\u0430 \u0432\u0435\u0441\u044C\u043C\u0430 \u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u043D\u043E \u0435\u0433\u043E \u0441\u043B\u043E\u0432\u0430 \u0440\u0430\u0441\u0441\u0435\u044E\u0442 \u0432\u0441\u0435 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F. \u041A\u0441\u0442\u0430\u0442\u0438, \u043F\u043E\u043B\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0430 \u0441\u043E\u0441\u0442\u0430\u0432\u0438\u043B \u043D\u0430 Svacchandatantra, \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A Svacchandoddyota. \u041E\u043D \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 15 pa\u1E6Dala-s, \u0438\u043B\u0438 \u0433\u043B\u0430\u0432, \u0438 \u0443\u0447\u0435\u043D\u044B\u0435 \u0437\u043D\u0430\u044E\u0442, \u0447\u0442\u043E \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0430 \u0431\u044B\u043B \u0435\u0433\u043E \u0430\u0432\u0442\u043E\u0440\u043E\u043C \u0441 \u0441\u0430\u043C\u043E\u0433\u043E \u043D\u0430\u0447\u0430\u043B\u0430, \u043A\u043E\u0433\u0434\u0430 \u043C\u0443\u0434\u0440\u0435\u0446 \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u0432 \u043F\u044F\u0442\u043E\u043C \u0441\u0442\u0438\u0445\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0432 \u043A\u043D\u0438\u0433\u0443: &quot;\u0915\u094D\u0937\u0947\u092E\u0930\u093E\u091C\u094B \u0935\u093F\u0935\u0943\u0923\u0941\u0924\u0947 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0928\u092F\u0902 \u092E\u0928\u093E\u0915\u094D\u0965\u096B\u0965 &quot; - &quot;K\u1E63emar\u0101jo viv\u1E5B\u1E47ute \u015Br\u012Bsvacchandanaya\u1E41 man\u0101k||5||&quot; - &quot;K\u1E63emar\u0101ja \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0433\u043E Svacchandatantra&quot;. \u0414\u0430, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0441\u043B\u043E\u0432\u043E man\u0101k (\u043D\u0435\u043C\u043D\u043E\u0433\u043E, \u0447\u0443\u0442\u044C-\u0447\u0443\u0442\u044C, \u0432 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438) \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u043A\u0430\u043A \u0441\u0432\u043E\u0435\u0433\u043E \u0440\u043E\u0434\u0430 \u0448\u0443\u0442\u043A\u0430, \u043E\u043D \u043F\u0440\u0430\u0432 \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0432\u0435\u043B\u0438\u043A\u0438\u0445 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u044B\u0445 \u0438 \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u0432, \u043D\u043E \u043D\u0435 \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0445 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437 \u043D\u0430\u0441, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0432\u0438\u0434\u044F \u0433\u043B\u0443\u0431\u0438\u043D\u0443 \u0438 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0441\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u044F, \u0434\u0430\u043D\u043D\u043E\u0433\u043E \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra, \u0434\u0430, \u043C\u0443\u0434\u0440\u0435\u0446 \u0431\u044B\u043B \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u043A\u0440\u0430\u0442\u043E\u043A (\u043E\u043A\u043E\u043B\u043E 2000 \u0441\u0442\u0440\u0430\u043D\u0438\u0446, \u044F \u043D\u0435 \u0448\u0443\u0447\u0443). \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0434\u043B\u044F \u0437\u0430\u043F\u0430\u0434\u043D\u043E\u0433\u043E \u0443\u043C\u0430, \u043F\u0440\u0438\u0432\u044B\u043A\u0448\u0435\u0433\u043E \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0447\u0438\u0442\u0430\u0442\u044C \u043A\u0440\u0430\u0442\u043A\u043E\u0435 \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0438\u0435, \u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0431\u0443\u0434\u0443\u0442 \u0432\u044B\u0433\u043B\u044F\u0434\u0435\u0442\u044C \u043E\u0447\u0435\u043D\u044C \u043E\u0431\u044A\u0435\u043C\u043D\u044B\u043C\u0438, \u043D\u043E \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u044C... \u043F\u043E\u043F\u0440\u043E\u0431\u0443\u0439\u0442\u0435 \u0431\u044B\u0442\u044C \u043E\u043F\u0442\u0438\u043C\u0438\u0441\u0442\u0438\u0447\u043D\u044B\u043C\u0438, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430, \u0445\u0430\u0445\u0430. \u041F\u0440\u043E\u0441\u0442\u0438, \u0413\u043E\u0441\u043F\u043E\u0434\u0438, \u043D\u043E \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0441\u0430\u0440\u043A\u0430\u0441\u0442\u0438\u0447\u043D\u044B\u043C \u0437\u0434\u0435\u0441\u044C \u0438 \u0448\u0443\u0442\u0438\u0442\u044C, \u0438\u043B\u0438 \u044F \u0443\u043C\u0440\u0443, \u0443\u0432\u0438\u0434\u0435\u0432 \u043A\u0440\u0430\u0442\u043A\u0438\u0439 \u0432\u0430\u0440\u0438\u0430\u043D\u0442 Svacchandoddyota \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441 \u043F\u0435\u0440\u0435\u0434\u043E \u043C\u043D\u043E\u0439. \u0414\u0430, \u043E\u043D \u043F\u0440\u044F\u043C\u043E \u043F\u0435\u0440\u0435\u0434\u043E \u043C\u043D\u043E\u0439 \u0441\u0435\u0439\u0447\u0430\u0441, \u0434\u0440\u0443\u0437\u044C\u044F. \u041A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0443\u0447\u0435\u043D\u0438\u0439 \u0438 \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u0438, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0439\u0441\u044F \u0432 \u044D\u0442\u043E\u0439 \u043A\u043D\u0438\u0433\u0435, \u2014 \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0448\u0435\u043B\u043E\u043C\u043B\u044F\u044E\u0449\u0435\u0435. \u041D\u0438 \u043E\u0434\u0438\u043D \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E &quot;\u043F\u043E\u043D\u044F\u0442\u044C&quot; \u044D\u0442\u0443 \u043A\u043D\u0438\u0433\u0443 \u0434\u0430\u0436\u0435 \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0439 \u0436\u0438\u0437\u043D\u0438, \u043D\u043E \u0441 \u0415\u0433\u043E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u044C\u044E, \u0432\u0441\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435.</li></ol><p>\u0422\u0435\u043F\u0435\u0440\u044C, \u0432\u0435\u0440\u043D\u0435\u043C\u0441\u044F \u043A \u0442\u0435\u043C\u0435 \u0441 \u0435\u0433\u043E &quot;\u043A\u0440\u0430\u0442\u043A\u0438\u043C&quot; \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u043C \u043D\u0430 VII, 297 (7-\u044E \u0433\u043B\u0430\u0432\u0443, \u0441\u0442\u0440\u043E\u0444\u0443 297). \u041F\u043E\u043C\u043D\u0438\u0442\u0435, \u0447\u0442\u043E \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0435 \u0441\u0442\u0440\u043E\u0444\u044B (\u0441 294-\u0439) Svacchandatantra \u0443\u0436\u0435 \u0431\u044B\u043B\u0438 \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u044B \u0432\u044B\u0448\u0435 [\u0441\u043C. &quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(p\u016Bryeta)</em> \u0447\u0435\u0440\u0435\u0437 \u043B\u0435\u0432\u0443\u044E [\u043D\u043E\u0437\u0434\u0440\u044E] <em>(apasavyena)</em> [\u0438] \u0432\u044B\u0434\u043E\u0445\u043D\u0443\u0442\u044C <em>(virecayet)</em> \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0430\u0432\u0443\u044E [\u043D\u043E\u0437\u0434\u0440\u044E]... [\u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435] \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F-- <em>(k\u1E5Btv\u0101)</em> \u043B\u0438\u0448\u0435\u043D\u043D\u0430\u044F \u0434\u0440\u043E\u0436\u0438 <em>(ni\u1E63kampam)</em> \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0430 \u0434\u044B\u0445\u0430\u043D\u0438\u044F <em>(kumbhakam... iti)</em>&quot;]. \u0418\u0442\u0430\u043A, \u0442\u0435\u0445\u043D\u0438\u043A\u0430, \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0435\u0439, \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 \u044D\u0442\u043E\u0439 \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 \u0434\u0440\u043E\u0436\u0430\u043D\u0438\u044F/\u0442\u0440\u0435\u043F\u0435\u0442\u0430\u043D\u0438\u044F \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0438 \u0434\u044B\u0445\u0430\u043D\u0438\u044F. \u041F\u0440\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u0441\u0442\u0440\u043E\u043A\u0443 297 \u0432 VII \u0433\u043B\u0430\u0432\u0435, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F:</p><blockquote><p>&quot; \u0928\u093F\u0937\u094D\u0915\u092E\u094D\u092A\u0915\u0941\u092E\u094D\u092D\u0915\u093E\u0928\u0928\u094D\u0924\u0930\u0902 \u0939\u0943\u0926\u092F\u0938\u091E\u094D\u091A\u093E\u0930\u093E\u0926\u093F\u0924\u093F \u0936\u0928\u0948\u0903 \u0936\u0928\u0948\u0930\u094D\u0939\u0943\u0926\u092F\u093E\u0926\u0927\u0903\u0938\u091E\u094D\u091A\u093E\u0930\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u092A\u094D\u0930\u093E\u0923\u0902 \u0928\u093E\u092D\u094D\u092F\u093E\u092E\u0947\u0935 \u0928\u093F\u092F\u092E\u094D\u092F\u0947\u0924\u094D\u092F\u0930\u094D\u0925\u093E\u0924\u094D\u0924\u0925\u093E \u092E\u0928 \u0907\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0917\u094B\u091A\u0930\u093E\u0926\u093F\u0924\u093F \u0924\u0924\u094D\u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0939\u093E\u0930\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0928\u093E\u092D\u094D\u092F\u093E\u092E\u0947\u0935 \u092E\u0928\u094B \u0928\u093F\u092F\u092E\u094D\u092F \u092E\u0928\u094B\u0928\u093F\u092F\u092E\u092A\u0942\u0930\u094D\u0935\u0915\u0902 \u092A\u094D\u0930\u093E\u0923\u0902 \u0928\u093E\u092D\u094C \u0928\u093F\u092F\u091A\u094D\u091B\u0924\u0903 \u0938\u0941\u092A\u094D\u0930\u0936\u093E\u0928\u094D\u0924\u0903 \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u094B \u092D\u0935\u0924\u093F\u0965\u0968\u096F\u096D\u0965 &quot; - &quot;Ni\u1E63kampakumbhak\u0101nantara\u1E41 h\u1E5Bdayasa\xF1c\u0101r\u0101diti \u015Banai\u1E25 \u015Banairh\u1E5Bday\u0101dadha\u1E25sa\xF1c\u0101rayukty\u0101 pr\u0101\u1E47a\u1E41 n\u0101bhy\u0101meva niyamyetyarth\u0101ttath\u0101 mana indriyagocar\u0101diti tatpraty\u0101h\u0101rayukty\u0101 n\u0101bhy\u0101meva mano niyamya manoniyamap\u016Brvaka\u1E41 pr\u0101\u1E47a\u1E41 n\u0101bhau niyacchata\u1E25 supra\u015B\u0101nta\u1E25 pr\u0101\u1E47\u0101y\u0101mo bhavati||297||&quot; - &quot;[\u042D\u0442\u0430 \u043F\u0440\u0430\u043D\u0430\u044F\u043C\u0430 (pr\u0101\u1E47\u0101y\u0101ma) \u043F\u0440\u043E\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0440\u0430\u0437\u0443 \u043F\u043E\u0441\u043B\u0435 \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 \u0434\u0440\u043E\u0436\u0438 \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0438 \u0434\u044B\u0445\u0430\u043D\u0438\u044F. [\u0412 \u0441\u0442\u0440\u043E\u0444\u0435,] &#39;h\u1E5Bdayasa\xF1c\u0101r\u0101t&#39; \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F &#39;\u041E\u0447\u0435\u043D\u044C \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0432 \u043F\u0443\u043F\u043A\u0435 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0435\u0440\u0435\u043D\u043E\u0441\u0430 --\u0442.\u0435. \u043F\u0435\u0440\u0435\u043C\u0435\u0449\u0430\u044F \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E-- \u043E\u0442 \u0441\u0435\u0440\u0434\u0446\u0430 \u043A\u043D\u0438\u0437\u0443 --\u0442.\u0435. \u0432\u043D\u0438\u0437 \u0434\u043E \u043F\u0443\u043F\u043A\u0430--&#39;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0430\u043A\u0436\u0435, &#39;mana indriyagocar\u0101t&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0443\u043C\u0430 \u0432 \u043F\u0443\u043F\u043A\u0435 \u0447\u0435\u0440\u0435\u0437 \u0435\u0433\u043E \u043E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u0435 \u043E\u0442 \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0442 \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432-- [\u043A \u043F\u0443\u043F\u043A\u0443]. \u0421\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044F \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044F \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u0432 \u043F\u0443\u043F\u043A\u0435, \u043D\u0430\u0440\u044F\u0434\u0443 \u0441\u043E \u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u0435\u043C \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C \u0443\u043C\u0430 [\u0442\u0430\u043C \u0436\u0435], \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043F\u0440\u0430\u043D\u0430\u044F\u043C\u0430 [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F] supra\u015B\u0101nta --\u043E\u0447\u0435\u043D\u044C \u0443\u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0448\u0435\u043D\u043D\u0430\u044F, \u0438\u043B\u0438 \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u0430\u044F||297||&quot;</p></blockquote><p>\u042D\u0442\u043E \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u043F\u0440\u0430\u043D\u0430\u044F\u043C\u0430 (pr\u0101\u1E47\u0101y\u0101ma) \u0438\u0437-\u0437\u0430 \u0435\u0435 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 \u0442\u0440\u0435\u0445 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0445 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445: \u0432\u044B\u0434\u043E\u0445\u0430, \u0432\u0434\u043E\u0445\u0430 \u0438 \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0438 \u0434\u044B\u0445\u0430\u043D\u0438\u044F. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0443\u044E \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A, \u043A\u0430\u043A \u044F \u044D\u0442\u043E \u0441\u0434\u0435\u043B\u0430\u043B.</p><ol start="7"><li>\u0421\u043B\u043E\u0432\u043E &quot;lak\u1E63a\u1E47a&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0437\u043D\u0430\u043A, \u0430\u0442\u0440\u0438\u0431\u0443\u0442, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430 \u0438 \u0442.\u0434.&quot;. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, &quot;lak\u1E63a\u1E47ai\u1E25&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u043B\u043E \u0431\u044B &quot;\u0447\u0435\u0440\u0435\u0437 \u0437\u043D\u0430\u043A\u0438, \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u044B, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0438 \u0438 \u0442.\u0434.&quot;. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u043B\u043E\u0432\u0430 &quot;lak\u1E63a\u1E47ai\u1E25&quot; \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u0441\u0442\u0440\u043E\u0444\u0443 Svacchandatantra:</li></ol><blockquote><p>&quot; \u0932\u0915\u094D\u0937\u0923\u0948\u0930\u093F\u0924\u093F \u092A\u094D\u0930\u0923\u0935\u093E\u0927\u093F\u0915\u093E\u0930\u094B\u0915\u094D\u0924\u0948\u0930\u0928\u0941\u092D\u0935\u0948\u0930\u094D\u092F\u0941\u091C\u094D\u092F\u0924 \u0907\u0924\u093F \u0936\u0947\u0937\u0903 &quot; - &quot;Lak\u1E63a\u1E47airiti pra\u1E47av\u0101dhik\u0101roktairanubhavairyujyata iti \u015Be\u1E63a\u1E25&quot; - &quot;[\u0421\u043B\u043E\u0432\u043E] &#39;lak\u1E63a\u1E47ai\u1E25&#39; [\u0432 \u0441\u0442\u0440\u043E\u0444\u0435] \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E &#39;\u043E\u043D \u043D\u0430\u0434\u0435\u043B\u0435\u043D \u043E\u043F\u044B\u0442\u043E\u043C, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u043C \u0432 Pra\u1E47av\u0101dhik\u0101ra --\u0442.\u0435. \u0432 \u0448\u0435\u0441\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 Svacchandatantra, \u0442\u0430\u043A\u0436\u0435 \u0438\u043D\u0432\u0435\u0441\u0442\u043D\u043E\u0439 \u043A\u0430\u043A Pa\xF1capra\u1E47av\u0101dhik\u0101ra--&#39;. \u042D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E [\u043A \u0441\u0442\u0440\u043E\u0444\u0435 \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430]&quot;</p></blockquote><p>\u0418\u0442\u0430\u043A, \u0441\u043C\u044B\u0441\u043B \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E Yog\u012B \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0442\u043A\u043D\u0443\u0442\u044C \u0432\u0441\u0435 \u0443\u0437\u043B\u044B (granthi-s) , \u0438 \u0442.\u0434. \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E Unman\u0101 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043E\u043D \u043D\u0430\u0434\u0435\u043B\u0435\u043D \u043E\u043F\u044B\u0442\u043E\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u0441 \u043A\u0430\u0436\u0434\u044B\u043C \u044D\u0442\u0430\u043F\u043E\u043C. \u042D\u0442\u043E\u0442 \u043E\u043F\u044B\u0442 \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0432 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 Svacchandatantra \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u043A\u0430\u043A \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u043F\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0414\u0443\u0445\u0430.</p></div>',1),n=[p];function o(h,u,i,y,c,s){return m(),e("div",null,n)}var k=a(r,[["render",o]]);export{v as __pageData,k as default};
